import{z as e}from"zod";export const GenreLayerSchema=e.enum(["universal","genre","book"]),GenreSeveritySchema=e.enum(["error","warning","info"]),GenreRuleContextSchema=e.object({storyBible:e.string().optional(),currentState:e.string().optional(),chapterIndex:e.number().int().min(0).optional(),genre:e.string().optional()}),GenreRuleViolationSchema=e.object({ruleId:e.string().min(1),severity:GenreSeveritySchema,message:e.string().min(1),location:e.string()});
